// build.gradle.kts (app module)
dependencies {
    // OkHttp BOM — controls versions of all okhttp artifacts
    implementation(platform("com.squareup.okhttp3:okhttp-bom:4.12.0"))
    implementation("com.squareup.okhttp3:okhttp")          // core + SSE
    implementation("com.squareup.okhttp3:logging-interceptor") // optional, for debug

    // JSON parsing — choose one
    implementation("com.google.code.gson:gson:2.10.1")
    // or: implementation("com.squareup.moshi:moshi-kotlin:1.15.1")

    // Coroutines
    implementation("org.jetbrains.kotlinx:kotlinx-coroutines-android:1.7.3")
}

import com.google.gson.annotations.SerializedName

// Request body
data class MessagesRequest(
    val model: String,
    @SerializedName("max_tokens") val maxTokens: Int,
    val messages: List<Message>,
    val stream: Boolean = true
)

data class Message(
    val role: String,   // "user" or "assistant"
    val content: String
)

// Streaming response events
data class StreamEvent(
    val type: String,          // e.g. "content_block_delta"
    val delta: Delta? = null,
    val index: Int? = null
)

data class Delta(
    val type: String,          // "text_delta"
    val text: String? = null
)

// Typed representation of events we care about
sealed class ClaudeStreamEvent {
    data class Token(val text: String) : ClaudeStreamEvent()
    data object StreamEnd : ClaudeStreamEvent()
    data class Error(val message: String) : ClaudeStreamEvent()
}

import com.google.gson.Gson
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.launch
import okhttp3.EventSource
import okhttp3.EventSourceListener
import okhttp3.Response

class ClaudeEventSourceListener(
    private val flow: MutableSharedFlow<ClaudeStreamEvent>,
    private val scope: CoroutineScope
) : EventSourceListener() {

    private val gson = Gson()

    // Called once when the SSE connection is established
    override fun onOpen(eventSource: EventSource, response: Response) {
        // Nothing to do — events arrive via onEvent
    }

    // Called for each SSE event line received
    override fun onEvent(
        eventSource: EventSource,
        id: String?,
        type: String?,
        data: String
    ) {
        // The SSE stream sends "[DONE]" as the final data line
        if (data == "[DONE]") {
            scope.launch { flow.emit(ClaudeStreamEvent.StreamEnd) }
            return
        }

        try {
            val event = gson.fromJson(data, StreamEvent::class.java)
            if (event.type == "content_block_delta") {
                val text = event.delta?.text ?: return
                scope.launch { flow.emit(ClaudeStreamEvent.Token(text)) }
            }
            // message_stop is the API-level end signal; [DONE] is the SSE transport end
            // Both arrive; handling [DONE] is sufficient for UI purposes
        } catch (e: Exception) {
            // Malformed JSON in a single event — log and continue
        }
    }

    // Called on connection failure or HTTP error
    override fun onFailure(
        eventSource: EventSource,
        t: Throwable?,
        response: Response?
    ) {
        val message = when {
            response != null -> "HTTP ${response.code}: ${response.message}"
            t != null        -> t.message ?: "Unknown error"
            else             -> "Unknown error"
        }
        scope.launch { flow.emit(ClaudeStreamEvent.Error(message)) }
    }

    // Called when the EventSource is closed (normally or after failure)
    override fun onClosed(eventSource: EventSource) {
        // No-op: StreamEnd or Error already emitted
    }
}

import com.google.gson.Gson
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.asSharedFlow
import okhttp3.EventSource
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.toRequestBody
import java.util.concurrent.TimeUnit

class ClaudeStreamingClient(
    private val apiKey: String,
    private val scope: CoroutineScope = CoroutineScope(Dispatchers.IO)
) {
    private val gson = Gson()
    private val json = "application/json".toMediaType()

    private val httpClient = OkHttpClient.Builder()
        .readTimeout(120, TimeUnit.SECONDS)  // SSE streams can last a long time
        .connectTimeout(15, TimeUnit.SECONDS)
        .build()

    fun streamMessage(
        userMessage: String,
        systemPrompt: String? = null,
        model: String = "claude-sonnet-4-6"
    ): Flow<ClaudeStreamEvent> {
        val sharedFlow = MutableSharedFlow<ClaudeStreamEvent>()

        val messages = mutableListOf<Message>()
        if (systemPrompt != null) {
            // System prompt goes in the messages list for simplicity;
            // or pass as the top-level "system" field in the request body.
        }
        messages.add(Message(role = "user", content = userMessage))

        val requestBody = MessagesRequest(
            model = model,
            maxTokens = 2048,
            messages = messages,
            stream = true
        )

        val request = Request.Builder()
            .url("https://api.anthropic.com/v1/messages")
            .post(gson.toJson(requestBody).toRequestBody(json))
            .header("x-api-key", apiKey)
            .header("anthropic-version", "2023-06-01")
            .header("Content-Type", "application/json")
            .build()

        val listener = ClaudeEventSourceListener(sharedFlow, scope)
        EventSource.Factory
            .create(request, listener)
            .let { /* event source auto-starts */ }

        // OkHttp's newEventSource opens the connection immediately
        httpClient.newCall(request)
            .let { /* handled by EventSource.Factory internally */ }

        // Use EventSources.createFactory to create and start:
        val factory = okhttp3.sse.EventSources.createFactory(httpClient)
        factory.newEventSource(request, listener)

        return sharedFlow.asSharedFlow()
    }
}

import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.callbackFlow
import okhttp3.sse.EventSources

fun OkHttpClient.streamClaude(
    request: Request,
    gson: Gson
): Flow<ClaudeStreamEvent> = callbackFlow {
    val listener = object : EventSourceListener() {
        override fun onEvent(
            eventSource: EventSource,
            id: String?,
            type: String?,
            data: String
        ) {
            if (data == "[DONE]") {
                trySend(ClaudeStreamEvent.StreamEnd)
                close()
                return
            }
            try {
                val event = gson.fromJson(data, StreamEvent::class.java)
                if (event.type == "content_block_delta") {
                    val text = event.delta?.text ?: return
                    trySend(ClaudeStreamEvent.Token(text))
                }
            } catch (_: Exception) { }
        }

        override fun onFailure(
            eventSource: EventSource,
            t: Throwable?,
            response: Response?
        ) {
            val msg = t?.message ?: "HTTP ${response?.code}"
            trySend(ClaudeStreamEvent.Error(msg))
            close(t)
        }

        override fun onClosed(eventSource: EventSource) {
            close()
        }
    }

    val eventSource = EventSources.createFactory(this@streamClaude)
        .newEventSource(request, listener)

    // Clean up the SSE connection when the collector cancels
    awaitClose { eventSource.cancel() }
}

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.Job
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch

data class ChatUiState(
    val response: String = "",
    val isStreaming: Boolean = false,
    val error: String? = null
)

class ChatViewModel(
    private val client: ClaudeStreamingClient
) : ViewModel() {

    private val _uiState = MutableStateFlow(ChatUiState())
    val uiState: StateFlow<ChatUiState> = _uiState.asStateFlow()

    private var streamJob: Job? = null

    fun sendMessage(text: String) {
        // Cancel any in-progress stream
        streamJob?.cancel()
        _uiState.update { it.copy(response = "", isStreaming = true, error = null) }

        streamJob = viewModelScope.launch {
            client.streamMessage(userMessage = text)
                .collect { event ->
                    when (event) {
                        is ClaudeStreamEvent.Token -> {
                            _uiState.update { state ->
                                state.copy(response = state.response + event.text)
                            }
                        }
                        is ClaudeStreamEvent.StreamEnd -> {
                            _uiState.update { it.copy(isStreaming = false) }
                        }
                        is ClaudeStreamEvent.Error -> {
                            _uiState.update {
                                it.copy(isStreaming = false, error = event.message)
                            }
                        }
                    }
                }
        }
    }

    fun cancelStream() {
        streamJob?.cancel()
        _uiState.update { it.copy(isStreaming = false) }
    }
}

@Composable
fun ChatScreen(viewModel: ChatViewModel = viewModel()) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    var inputText by remember { mutableStateOf("") }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
    ) {
        // Streaming response area
        Box(
            modifier = Modifier
                .weight(1f)
                .fillMaxWidth()
                .verticalScroll(rememberScrollState())
        ) {
            if (uiState.error != null) {
                Text(
                    text = "Error: ${uiState.error}",
                    color = MaterialTheme.colorScheme.error
                )
            } else {
                Text(
                    text = uiState.response,
                    modifier = Modifier.fillMaxWidth()
                )
            }
        }

        // Streaming indicator
        if (uiState.isStreaming) {
            LinearProgressIndicator(modifier = Modifier.fillMaxWidth())
        }

        // Input row
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            OutlinedTextField(
                value = inputText,
                onValueChange = { inputText = it },
                modifier = Modifier.weight(1f),
                label = { Text("Message") },
                enabled = !uiState.isStreaming
            )
            if (uiState.isStreaming) {
                Button(onClick = { viewModel.cancelStream() }) {
                    Text("Stop")
                }
            } else {
                Button(
                    onClick = {
                        if (inputText.isNotBlank()) {
                            viewModel.sendMessage(inputText)
                            inputText = ""
                        }
                    }
                ) {
                    Text("Send")
                }
            }
        }
    }
}

// Replace the direct Anthropic URL with your backend proxy
private val PROXY_URL = "https://api.yourapp.com/ai/stream"

fun streamMessage(userMessage: String): Flow<ClaudeStreamEvent> {
    val body = gson.toJson(mapOf("message" to userMessage)).toRequestBody(json)

    val request = Request.Builder()
        .url(PROXY_URL)
        .post(body)
        // Your own session token — not the Anthropic key
        .header("Authorization", "Bearer ${SessionStore.currentToken}")
        .header("Content-Type", "application/json")
        .build()

    return httpClient.streamClaude(request, gson)
}
// The backend adds x-api-key and anthropic-version before forwarding to Anthropic.

import app.cash.turbine.test
import com.google.gson.Gson
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.test.runTest
import okhttp3.EventSource
import okhttp3.Response
import org.junit.Test
import org.mockito.kotlin.mock

class ClaudeEventSourceListenerTest {

    private val gson = Gson()

    @Test
    fun `onEvent emits Token for content_block_delta`() = runTest {
        val flow = MutableSharedFlow<ClaudeStreamEvent>(replay = 10)
        val listener = ClaudeEventSourceListener(flow, this)
        val fakeSource = mock<EventSource>()

        val data = gson.toJson(StreamEvent(
            type = "content_block_delta",
            delta = Delta(type = "text_delta", text = "Hello")
        ))
        listener.onEvent(fakeSource, null, "content_block_delta", data)

        flow.test {
            val event = awaitItem()
            assert(event is ClaudeStreamEvent.Token)
            assert((event as ClaudeStreamEvent.Token).text == "Hello")
        }
    }

    @Test
    fun `[DONE] emits StreamEnd`() = runTest {
        val flow = MutableSharedFlow<ClaudeStreamEvent>(replay = 10)
        val listener = ClaudeEventSourceListener(flow, this)
        val fakeSource = mock<EventSource>()

        listener.onEvent(fakeSource, null, null, "[DONE]")

        flow.test {
            assert(awaitItem() is ClaudeStreamEvent.StreamEnd)
        }
    }
}
